#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<string> letterCombinations(string digits) {
        if (digits.empty()) {
            return {};
        }
        unordered_map<char, string> phone = {
            {'2', "abc"},
            {'3', "def"},
            {'4', "ghi"},
            {'5', "jkl"},
            {'6', "mno"},
            {'7', "pqrs"},
            {'8', "tuv"},
            {'9', "wxyz"}
        };
        vector<string> res = {""};
        for (char d : digits) {
            vector<string> tmp;
            for (const string& r : res) {
                for (char c : phone[d]) {
                    tmp.push_back(r + c);
                }
            }
            res = tmp;
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string digits;
    if (!(cin >> digits)) return 0;
    Solution sol;
    vector<string> ans = sol.letterCombinations(digits);
    cout << ans.size() << endl;
    for (size_t i = 0; i < ans.size(); ++i) {
        cout << ans[i];
        if (i != ans.size() - 1) {
            cout << ",";
        }
    }
    cout << endl;
    return 0;
}
